#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

my $cgi = new CGI;

# Accept log filename from query parameters using param('logfile')
my $filename = $cgi->param('logfile');
my $log_dir = "/path/to/your/directory";  # Replace with your actual directory path
my $file_path = "$log_dir/$filename";

# Open the file with open(FH, "$log_dir/$filename")
open(FH, '<', $file_path) or die "Could not open file '$file_path': $!";

print $cgi->header(-type => "text/html", -charset => "utf-8"),
        $cgi->start_html("Log Viewer: $filename"),
        "<pre>";  # display content for our web-based log viewer.
        
while (my $line = <FH>) {  
    print $line;            
}                         
print "</pre></body></html>";

close FH;